I cannot directly render 3D graphics or execute code that produces a visual output in this text-based interface. However, I can provide you with the **code** to render a 3D house using popular libraries like **Three.js** (for the web) or **Blender** (for offline 3D modeling).

Below is a complete, single-file HTML/JavaScript solution using **Three.js**. You can save this code as an `.html` file and open it in any modern web browser to see the 3D house.

### How to use this:
1.  Copy the code block below.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click and drag to rotate • Scroll to zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xeeeeee });
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 });
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x5c3a21 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, grassMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Main Body
        const bodyGeo = new THREE.BoxGeometry(8, 6, 8);
        const body = new THREE.Mesh(bodyGeo, wallMaterial);
        body.position.y = 3;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // Roof
        const roofGeo = new THREE.ConeGeometry(7, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        houseGroup.add(roof);

        // Windows
        function createWindow(x, z, y, w, h) {
            const winGeo = new THREE.BoxGeometry(w, h, 0.2);
            const win = new THREE.Mesh(winGeo, windowMaterial);
            win.position.set(x, y, z);
            houseGroup.add(win);
        }

        createWindow(2.5, 2.5, 3.5, 2, 2.5); // Front Left
        createWindow(-2.5, 2.5, 3.5, 2, 2.5); // Front Right
        createWindow(2.5, -2.5, 3.5, 2, 2.5); // Back Left
        createWindow(-2.5, -2.5, 3.5, 2, 2.5); // Back Right

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 3.5, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 1.75, 4.1);
        houseGroup.add(door);

        // 6. Add House to Scene
        scene.add(houseGroup);

        // 7. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### What this code does:
1.  **Sets up a Scene:** Creates a 3D environment with a sky-blue background and fog.
2.  **Adds Lighting:** Uses an ambient light for general visibility and a directional light (sun) to create shadows.
3.  **Constructs Geometry:**
    *   **Floor:** A green box representing grass.
    *   **Walls:** A white box for the main structure.
    *   **Roof:** A cone shape rotated to look like a pyramid roof.
    *   **Details:** Adds blue semi-transparent boxes for windows and a brown box for the door.
4.  **Interactivity:** Includes `OrbitControls`, allowing you to click and drag to rotate around the house and scroll to zoom in/out.

